package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import org.joda.time.LocalDate;
import org.joda.time.Weeks;

import java.math.BigDecimal;

public class AantalRszDagen {
    public static BigDecimal inMaand(int rszDagenStelsel, LocalDateInterval rekenPeriode) {
        LocalDateInterval maand = new Month(rekenPeriode.getStart());
        return inInterval(maand, rszDagenStelsel);
    }

    public static BigDecimal inMaand(Opper opper, LocalDateInterval rekenPeriode) {
        int rszDagenStelsel = opper.getWeddeBerekening().getRszDagenStelsel();
        return inMaand(rszDagenStelsel, rekenPeriode);
    }

    public static BigDecimal inJaar(int rszDagenStelsel, LocalDateInterval rekenPeriode) {
        LocalDate beginDagJaar = rekenPeriode.getStart().withDayOfYear(1);
        LocalDate eindDagJaar = beginDagJaar.plusYears(1).minusDays(1);
        LocalDateInterval jaar = new LocalDateInterval(beginDagJaar, eindDagJaar);
        return inInterval(jaar, rszDagenStelsel);
    }

    public static BigDecimal inInterval(LocalDateInterval interval, int rszDagenStelsel) {
        LocalDate beginDag = interval.getStart();
        LocalDate eindDag = interval.getEnd();
        int beginDagNr = beginDag.getDayOfWeek();
        int eindDagNr = eindDag.getDayOfWeek();

        LocalDate beginVolleWeken = beginDag.plusDays(7 - beginDagNr);
        LocalDate eindVolleWeken = eindDag.minusDays(eindDagNr);
        int rszDagen = 0;
        if (!beginVolleWeken.isAfter(eindVolleWeken)) {
            LocalDateInterval volleWeken = new LocalDateInterval(beginVolleWeken, eindVolleWeken);
            rszDagen = Weeks.weeksIn(volleWeken.getJodaInterval()).getWeeks() * rszDagenStelsel;
            if (beginDagNr <= rszDagenStelsel) {
                rszDagen += rszDagenStelsel + 1 - beginDagNr;
            }
            rszDagen += Math.min(eindDagNr, rszDagenStelsel);
        } else if (beginDagNr <= rszDagenStelsel) {
            rszDagen = Math.min(eindDagNr, rszDagenStelsel) + 1 - beginDagNr;
        }
        return BigDecimal.valueOf(rszDagen);
    }
}
